import { render } from '../../core/engine.js';
import { state, salons, masters, services, timeSlots, users } from '../../state.js';
import { showToast, getSalonPrice, formatDate, validatePhone } from '../../utils.js';

export function goToBookingStep(step) {
    const bd = state.bookingData;
    
    // Валидация при движении ВПЕРЕД
    if (step > state.bookingStep) {
        if (state.bookingStep === 1 && !bd.serviceId) { showToast('Выберите услугу'); return; }
        if (state.bookingStep === 3 && !bd.date) { showToast('Выберите дату'); return; }
        if (state.bookingStep === 4 && !bd.time) { showToast('Выберите время'); return; }
    }

    // Если бронируем мастера напрямую, можно пропустить шаг 2 (выбор мастера)
    if (bd.type === 'master') {
        if (step === 2 && state.bookingStep === 1) step = 3; // От услуг сразу к календарю
        if (step === 2 && state.bookingStep === 3) step = 1; // Назад от календаря к услугам
    } else {
        // Если бронируем салон, мастер по умолчанию "Любой" (null), если еще не выбран
        if (step === 3 && state.bookingStep === 2 && bd.masterId === undefined) {
            bd.masterId = null;
        }
    }

    state.bookingStep = step;
    render();
}

window.goToBookingStep = goToBookingStep;

export function nextStepDefault() {
    const bd = state.bookingData;
    const step = state.bookingStep;
    
    if (step === 1) {
        if (!bd.serviceId) {
            let availableServices = [];
            if (bd.type === 'salon') {
                const salon = window.salons?.find(s => s.id === bd.targetId);
                if (salon) availableServices = window.services?.filter(s => salon.categories.includes(s.category)) || [];
            } else if (bd.type === 'master') {
                const master = window.masters?.find(m => m.id === bd.targetId);
                if (master) availableServices = window.services?.filter(s => master.services.includes(s.id)) || [];
            }
            if (availableServices.length > 0) bd.serviceId = availableServices[0].id;
        }
        if (bd.serviceId) goToBookingStep(step + (bd.type === 'master' ? 2 : 1));
        else { showToast('Нет доступных услуг'); return; }
    } else if (step === 2) {
        if (bd.masterId === undefined) bd.masterId = null;
        goToBookingStep(3);
    } else if (step === 3) {
        if (!bd.date) {
            bd.date = new Date();
            bd.date.setHours(0,0,0,0);
        }
        goToBookingStep(4);
    } else if (step === 4) {
        if (!bd.time) {
            const slots = window.timeSlots || [];
            if (slots.length > 0) bd.time = slots[0];
        }
        if (bd.time) goToBookingStep(5);
        else { showToast('Время не найдено'); return; }
    }
}

window.nextStepDefault = nextStepDefault;

export function submitBooking() {
    const bd = state.bookingData;
    const nameInput = document.getElementById('clientNameInput');
    if (nameInput) bd.clientName = nameInput.value;
    const phoneInput = document.getElementById('clientPhoneInput') || document.getElementById('bookingPhoneInput');
    if (phoneInput) bd.clientPhone = phoneInput.value;

    
    let phoneDigits = (bd.clientPhone || '').replace(/\D/g, '');
    let nameVal = (bd.clientName || '').trim();
    if (!nameVal || phoneDigits.length < 12) {
        showToast('Пожалуйста, заполните имя и корректный номер телефона');
        return;
    }

    if (bd.editingId) {
        // РЕЖИМ РЕДАКТИРОВАНИЯ
        const bIndex = state.bookings.findIndex(b => b.id === bd.editingId);
        if (bIndex !== -1) {
            state.bookings[bIndex] = {
                ...state.bookings[bIndex],
                serviceId: bd.serviceId,
                masterId: bd.masterId,
                date: formatDate(bd.date),
                time: bd.time,
                clientName: bd.clientName,
                clientPhone: bd.clientPhone,
                clientComment: bd.clientComment,
                status: 'pending' // Сбрасываем статус на проверку
            };
            showToast('Запись успешно обновлена!');
        }
    } else {
        // РЕЖИМ НОВОЙ ЗАПИСИ
        const booking = {
            id: generateId(),
            type: bd.type,
            targetId: bd.targetId,
            serviceId: bd.serviceId,
            masterId: bd.masterId,
            date: formatDate(bd.date),
            time: bd.time,
            clientName: bd.clientName,
            clientPhone: bd.clientPhone,
            clientComment: bd.clientComment,
            status: (state.currentUser && ['salon', 'master'].includes(state.currentUser.role)) ? 'confirmed' : 'pending',
            createdAt: new Date().toISOString(),
            clientUserId: (state.currentUser && state.currentUser.role === 'client') ? state.currentUser.id : null
        };
        
        if (!state.currentUser) {
            booking.trackingCode = Math.random().toString(36).substring(2, 8).toUpperCase();
        }
        
        state.bookings.push(booking);
        state.lastBooking = booking;
        
        // Save guest details
        if (!state.currentUser) {
            localStorage.setItem('guestClientName', bd.clientName);
            localStorage.setItem('guestClientPhone', bd.clientPhone);
            const gb = JSON.parse(localStorage.getItem('guestBookings') || '[]');
            gb.push(booking.id);
            localStorage.setItem('guestBookings', JSON.stringify(gb));
        }
    
    }
    
    // Go to success step instead of closing
    state.bookingStep = 6;
    
    render();
}

window.submitBooking = submitBooking;

export function closeBookingModal(event) {
    if (event && event.target !== event.currentTarget) return;
    state.bookingModal = false;
    state.bookingStep = 1;
    document.body.style.overflow = '';
    render();
}

window.closeBookingModal = closeBookingModal;

export function cancelBooking(bookingId) {
    const booking = state.bookings.find(b => b.id === bookingId);
    if (booking) { 
        booking.status = 'cancelled'; 
        showToast('Запись отменена'); 
        try {
            const gb = JSON.parse(localStorage.getItem('guestBookings')||'[]');
            const index = gb.findIndex(g => g.id === booking.id);
            if (index !== -1) {
                gb[index] = booking;
                localStorage.setItem('guestBookings', JSON.stringify(gb));
            }
        } catch(e){}
        render(); 
    }
}

window.cancelBooking = cancelBooking;

export function trackBooking() {
    const input = document.getElementById('trackingCodeInput');
    if (!input || !input.value.trim()) return showToast('Введите код отслеживания');
    const code = input.value.trim().toUpperCase();
    
    const booking = state.bookings.find(b => b.trackingCode === code);
    if (!booking) return showToast('Запись с таким кодом не найдена');
    
    state.trackModalTarget = booking;
    render();
}

window.trackBooking = trackBooking;

