export function changeMonth(delta) {
    let m = (state._calMonth !== undefined ? state._calMonth : new Date().getMonth()) + delta;
    let y = state._calYear || new Date().getFullYear();
    if (m < 0) { m = 11; y--; }
    if (m > 11) { m = 0; y++; }
    state._calMonth = m;
    state._calYear = y;
    render();
}

window.changeMonth = changeMonth;

